import anthropic
import json

client = anthropic.Anthropic()

# ---------------------------------------------------------------------------
# Tool definitions — each is a dict the API accepts directly
# ---------------------------------------------------------------------------
TOOLS = [
    {
        "name": "get_weather",
        "description": (
            "Returns the current weather for a city. Use this when the user asks "
            "about current weather conditions, temperature, or forecast. "
            "Does NOT provide historical weather data."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "city": {
                    "type": "string",
                    "description": "The city name, e.g. 'London' or 'New York'.",
                },
                "units": {
                    "type": "string",
                    "enum": ["celsius", "fahrenheit"],
                    "description": "Temperature unit. Defaults to celsius if not specified.",
                },
            },
            "required": ["city"],
        },
    },
    {
        "name": "search_knowledge_base",
        "description": (
            "Searches the internal product knowledge base for documentation, FAQs, "
            "and policy articles. Use when the user asks a product-specific question "
            "that may be answered by internal docs. Returns up to 3 ranked snippets."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {
                    "type": "string",
                    "description": "A concise search query derived from the user's question.",
                },
                "max_results": {
                    "type": "integer",
                    "description": "Number of results to return. Must be between 1 and 5.",
                    "minimum": 1,
                    "maximum": 5,
                },
            },
            "required": ["query"],
        },
    },
]


# ---------------------------------------------------------------------------
# Simulated tool implementations
# ---------------------------------------------------------------------------
def get_weather(city: str, units: str = "celsius") -> dict:
    # In production this would call a real weather API
    return {"city": city, "temp": 18, "units": units, "condition": "partly cloudy"}


def search_knowledge_base(query: str, max_results: int = 3) -> list[dict]:
    return [{"title": "Refund Policy", "snippet": "Refunds are processed within 5 business days."}]


def dispatch_tool(name: str, inputs: dict):
    if name == "get_weather":
        return get_weather(**inputs)
    if name == "search_knowledge_base":
        return search_knowledge_base(**inputs)
    raise ValueError(f"Unknown tool: {name}")


# ---------------------------------------------------------------------------
# Agentic loop: send message, handle tool calls, return final answer
# ---------------------------------------------------------------------------
def run(user_message: str) -> str:
    messages = [{"role": "user", "content": user_message}]

    while True:
        response = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=400,
            tools=TOOLS,
            messages=messages,
        )

        if response.stop_reason == "end_turn":
            return next(b.text for b in response.content if hasattr(b, "text"))

        # Collect tool uses
        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                result = dispatch_tool(block.name, block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": json.dumps(result),
                })

        # Append assistant turn and tool results, then continue
        messages.append({"role": "assistant", "content": response.content})
        messages.append({"role": "user", "content": tool_results})


print(run("What's the weather like in Tokyo right now?"))
print(run("How long do refunds take?"))
